parameters.jsCode:
// Prepare comprehensive audit log data
const items = $input.all();
const auditEntries = [];

for (const item of items) {
  const auditEntry = {
    timestamp: new Date().toISOString(),
    workflow_execution_id: $execution.id,
    workflow_path: item.json.workflow_path || 'unknown',

    // Validation results from Content Signal Agent
    validation_status: item.json.validation_status || item.json.status,
    content_id: item.json.content_id,
    content_type: item.json.content_type,
    content_text: item.json.content_text || item.json.content,

    // Governance decisions
    governance_decision: item.json.governance_decision || item.json.decision,
    policy_violations: item.json.policy_violations || [],
    severity_level: item.json.severity_level || item.json.severity,
    confidence_score: item.json.confidence_score || item.json.confidence,

    // Enforcement actions
    enforcement_action: item.json.enforcement_action || item.json.action,
    action_type: item.json.action_type,
    action_reason: item.json.action_reason || item.json.reason,

    // Escalation status
    escalation_required: item.json.escalation_required || false,
    escalation_status: item.json.escalation_status || 'none',
    escalation_notified: item.json.escalation_notified || false,

    // Additional metadata
    user_id: item.json.user_id,
    platform: item.json.platform,
    reviewed_by: item.json.reviewed_by || 'ai_agent',
    review_notes: item.json.review_notes || item.json.notes
  };

  auditEntries.push({ json: auditEntry });
}

return auditEntries;
